import{_ as t,o as n,c as a,a3 as r}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"73A. Gender Affirmation","description":"","frontmatter":{"title":"73A. Gender Affirmation","eba":"Nurses and Midwives 2024-2028","topics":["leave","gender-affirmation-leave"]},"headers":[],"relativePath":"ebas/nurses-midwives/leave/73A-gender-affirmation.md","filePath":"ebas/nurses-midwives/leave/73A-gender-affirmation.md"}'),o={name:"ebas/nurses-midwives/leave/73A-gender-affirmation.md"};function i(s,e,p,d,m,l){return n(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="_73a-gender-affirmation" tabindex="-1">73A. Gender Affirmation <a class="header-anchor" href="#_73a-gender-affirmation" aria-label="Permalink to &quot;73A. Gender Affirmation&quot;">​</a></h1><p>This clause applies from 24 June 2024.</p><p><strong>73A.1</strong> The Employer encourages a culture that is supportive of transgender and gender diverse Employees and recognises the importance of providing a safe environment for Employees undertaking gender affirmation.</p><p><strong>73A.2</strong> Gender affirmation refers to the process where an Employee commences living as a member of another gender. This is sometimes referred to ‘affirming’ their gender. This may occur through medical, social or legal changes.</p><p><strong>73A.3</strong> Employees may give effect to their affirmation in a number of ways and are not required to be undergoing specific types of changes, such as surgery, to access leave under this clause.</p><p><strong>73A.4</strong> Amount of gender affirmation leave</p><p><strong>(a)</strong> An Employee (other than a Casual Employee is entitled to Gender Affirmation Leave for the purpose of supporting the Employee’s affirmation in accordance with subclause 73A.4(c) below. Gender Affirmation Leave will comprise:</p><p><strong>(i)</strong> up to 20 days&#39; paid leave for essential and necessary gender affirmation procedures; and</p><p><strong>(ii)</strong> up to 48 weeks of unpaid leave.</p><p><strong>(b)</strong> The Gender Affirmation Leave entitlements outlined in clause 73A.4 are available to be taken by the Employee within the first 52 weeks after they commence Essential gender affirmation procedures.</p><p><strong>(c)</strong> Essential gender affirmation procedures may include:</p><p><strong>(i)</strong> medical or psychological appointments; or</p><p><strong>(ii)</strong> hormonal appointments; or</p><p><strong>(iii)</strong> surgery and associated appointments; or</p><p><strong>(iv)</strong> appointments to alter the Employee’s legal status or amend the Employee’s gender on legal documentation; or</p><p><strong>(v)</strong> any other similar necessary appointment or procedure to give effect to the Employee’s affirmation as agreed with the Employer.</p><p><strong>(d)</strong> An Employee who is entitled to unpaid Gender Affirmation Leave may, in conjunction with all or part of that leave utilise accrued Annual or Long Service Leave, provided that the combined total of all paid and unpaid leave taken does not exceed 52 continuous weeks. This period can be extended by agreement</p><p>between the Employer and the Employee (agreement will not unreasonably withheld).</p><p><strong>(e)</strong> Gender Affirmation Leave may be taken as consecutive, single or part days as agreed with the Employer.</p><p><strong>(f)</strong> Leave under this clause will not accrue from year to year and cannot be cashed out on termination of employment.</p><p><strong>73A.5</strong> Gender Affirmation Leave – Casual Employees</p><p>Casual Employees are entitled to access unpaid leave of up to 52 continuous weeks duration for gender affirmation purposes.</p><p><strong>73A.6</strong> Notice and evidence requirements</p><p><strong>(a)</strong> An Employee seeking to access Gender Affirmation Leave must provide the Employer with at least 4 weeks’ written notice of their intended commencement date and expected period of leave, unless otherwise agreed by the Employer.</p><p><strong>(b)</strong> An Employee seeking to access Gender Affirmation Leave may be required to provide suitable supporting documentation or evidence of their attendance at essential gender affirmation procedures. This may be in the form of a document issued by a Registered Health Practitioner, a lawyer, or a State, Territory or Federal government organisation, statutory declaration or other suitable supporting documentation.</p><p>Plain language terms: transition leave, trans leave, gender transition, gender reassignment.</p>',26)])])}const c=t(o,[["render",i]]);export{g as __pageData,c as default};
